Multiplayer Game Server
========================

This is a simple example of a multiplayer game server using Node.js and Socket.io. It allows multiple players to connect and send messages to each other.

Prerequisites
-------------

- Node.js installed
- Socket.io installed

Installation
------------

1. Create a new directory for your project.
2. Initialize a new Node.js project by running `npm init -y`.
3. Install Socket.io by running `npm install socket.io`.
4. Create a new file called `server.js` and add the following code:

```javascript
const http = require('http');
const socketIo = require('socket.io');

const server = http.createServer();
const io = socketIo(server);

io.on('connection', (socket) => {
  console.log('A user connected');

  socket.on('chat message', (msg) => {
    io.emit('chat message', msg);
  });

  socket.on('disconnect', () => {
    console.log('User disconnected');
  });
});

server.listen(3000, () => {
  console.log('Server listening on port 3000');
});
```

5. Create a new file called `index.html` and add the following code:

```html
<!DOCTYPE html>
<html>
  <head>
    <title>Multiplayer Game Server</title>
    <script src="/socket.io/socket.io.js"></script>
    <script>
      var socket = io();

      var form = document.getElementById('form');
      var input = document.getElementById('myInput');
      var messages = document.getElementById('messages');

      form.addEventListener('submit', function(e) {
        e.preventDefault();
        socket.emit('chat message', input.value);
        input.value = '';
      });

      socket.on('chat message', function(msg) {
        var item = document.createElement('li');
        item.textContent = msg;
        messages.appendChild(item);
      });
    </script>
  </head>
  <body>
    <form id="form" action="">
      <input id="myInput" autocomplete="off" /><button>Send</button>
    </form>
    <ul id="messages"></ul>
  </body>
</html>
```

6. Run the server by running `node server.js`.
7. Open your browser and navigate to `http://localhost:3000`.

Usage
-----

1. Open multiple browser windows and navigate to `http://localhost:3000`.
2. Type a message in the input field and click the "Send" button.
3. The message will be sent to all connected clients.

This is a simple example of a multiplayer game server using Node.js and Socket.io. You can expand on this example by adding more features such as user authentication, game logic, and more.

Multi-User Chat (MUC) Protocol Implementation

The following implementation demonstrates a basic Multi-User Chat (MUC) protocol using XMPP (Extensible Messaging and Presence Protocol) standards. This example focuses on the core functionality of creating, joining, and managing chat rooms.

### 1. Server-Side Implementation (Node.js with `xmpp.js`)

```javascript
const xmpp = require('xmpp.js');

class MUCServer {
  constructor(config) {
    this.server = new xmpp.Server(config);
    this.rooms = new Map();
    this.setupHandlers();
  }

  setupHandlers() {
    // Handle room creation
    this.server.on('iq', (stanza) => {
      if (stanza.getAttribute('type') === 'set' && stanza.querySelector('create')) {
        this.createRoom(stanza);
      }
    });

    // Handle room joining
    this.server.on('presence', (stanza) => {
      if (stanza.querySelector('join')) {
        this.joinRoom(stanza);
      }
    });

    // Handle messages
    this.server.on('message', (stanza) => {
      if (stanza.getAttribute('type') === 'chat') {
        this.handleMessage(stanza);
      }
    });
  }

  createRoom(stanza) {
    const roomJid = stanza.querySelector('create').getAttribute('jid');
    const room = {
      jid: roomJid,
      occupants: new Map(),
      history: []
    };
    this.rooms.set(roomJid, room);
    console.log(`Room created: ${roomJid}`);
  }

  joinRoom(stanza) {
    const roomJid = stanza.getAttribute('to');
    const userJid = stanza.getAttribute('from');
    const room = this.rooms.get(roomJid);

    if (!room) {
      this.sendPresenceError(stanza, 'room-not-found');
      return;
    }

    room.occupants.set(userJid, {
      nickname: stanza.querySelector('nick')?.textContent || 'Anonymous',
      presence: 'available'
    });

    // Send presence to all occupants
    room.occupants.forEach((occupant, occupantJid) => {
      const presence = new xmpp.Presence({
        from: userJid,
        to: occupantJid,
        type: 'available'
      });
      this.server.send(presence);
    });
  }

  handleMessage(stanza) {
    const roomJid = stanza.getAttribute('to');
    const room = this.rooms.get(roomJid);

    if (!room) return;

    // Broadcast message to all occupants
    room.occupants.forEach((occupant, occupantJid) => {
      const message = new xmpp.Message({
        from: stanza.getAttribute('from'),
        to: occupantJid,
        type: 'chat',
        body: stanza.querySelector('body')?.textContent
      });
      this.server.send(message);
    });
  }

  sendPresenceError(stanza, errorType) {
    const error = new xmpp.Error({
      type: 'cancel',
      condition: errorType
    });
    this.server.send(error);
  }
}

// Initialize server
const mucServer = new MUCServer({
  hostname: 'localhost',
  port: 5222,
  domain: 'muc.example.com'
});

mucServer.server.start();
```

### 2. Client-Side Implementation (XMPP.js)

```javascript
const xmpp = require('xmpp.js');

class MUCClient {
  constructor(jid, password) {
    this.connection = new xmpp.Client({
      jid: jid,
      password: password,
      host: 'muc.example.com',
      port: 5222
    });
    this.setupHandlers();
  }

  setupHandlers() {
    this.connection.on('connect', () => {
      console.log('Connected to MUC server');
    });

    this.connection.on('presence', (stanza) => {
      if (stanza.getAttribute('type') === 'available') {
        console.log(`User ${stanza.getAttribute('from')} is available`);
      }
    });

    this.connection.on('message', (stanza) => {
      if (stanza.getAttribute('type') === 'chat') {
        console.log(`Message from ${stanza.getAttribute('from')}: ${stanza.querySelector('body')?.textContent}`);
      }
    });
  }

  joinRoom(roomJid, nickname) {
    const presence = new xmpp.Presence({
      to: roomJid,
      type: 'available',
      join: true,
      nick: nickname
    });
    this.connection.send(presence);
  }

  sendMessage(roomJid, message) {
    const msg = new xmpp.Message({
      to: roomJid,
      type: 'chat',
      body: message
    });
    this.connection.send(msg);
  }

  leaveRoom(roomJid) {
    const presence = new xmpp.Presence({
      to: roomJid,
      type: 'unavailable'
    });
    this.connection.send(presence);
  }
}

// Usage example
const client = new MUCClient('user@example.com', 'password');
client.joinRoom('room1@muc.example.com', 'User1');
client.sendMessage('room1@muc.example.com', 'Hello, everyone!');
```

### 3. Protocol Features

- **Room Creation**: Users can create new chat rooms with unique JIDs.
- **Room Joining**: Users can join existing rooms and receive presence updates.
- **Message Broadcasting**: Messages sent to a room are broadcast to all occupants.
- **Presence Management**: Users can track who is online and offline in a room.
- **Error Handling**: Proper error responses for invalid room requests.

### 4. Security Considerations

- **Authentication**: Ensure proper authentication mechanisms are in place.
- **Encryption**: Use TLS/SSL for secure communication.
- **Access Control**: Implement room access controls (e.g., password-protected rooms).
- **Rate Limiting**: Prevent abuse by limiting message frequency.

This implementation provides a foundation for building a robust Multi-User Chat system using XMPP standards. You can extend it with additional features like room moderation, message history, and file sharing.

Multiplayer Game Server
```csharp
using System;
using System.Net;
using System.Net.Sockets;
using System.Text;
using System.Threading;

namespace MultiplayerGameServer
{
    class Program
    {
        static void Main(string[] args)
        {
            Console.WriteLine("Multiplayer Game Server Starting...");
            Console.WriteLine("Listening on port 8888");

            TcpListener server = new TcpListener(IPAddress.Any, 8888);
            server.Start();

            while (true)
            {
                Console.WriteLine("Waiting for client connection...");
                TcpClient client = server.AcceptTcpClient();
                Console.WriteLine("Client connected!");

                Thread clientThread = new Thread(() => HandleClient(client));
                clientThread.IsBackground = true;
                clientThread.Start();
            }
        }

        static void HandleClient(TcpClient client)
        {
            NetworkStream stream = client.GetStream();
            byte[] buffer = new byte[1024];
            int bytesRead;

            try
            {
                while ((bytesRead = stream.Read(buffer, 0, buffer.Length)) > 0)
                {
                    string message = Encoding.UTF8.GetString(buffer, 0, bytesRead);
                    Console.WriteLine($"Received from client: {message}");

                    // Echo back the message
                    byte[] response = Encoding.UTF8.GetBytes($"Server received: {message}");
                    stream.Write(response, 0, response.Length);
                }
            }
            catch (Exception ex)
            {
                Console.WriteLine($"Error handling client: {ex.Message}");
            }
            finally
            {
                client.Close();
            }
        }
    }
}
